fn test_stale_retry_timer_is_ignored() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let now_ms = 20_000;

    let current_token = orchestrator.schedule_retry(
        "issue-stale-retry",
        "SIM-50",
